checkConstraint.constraint:
 (
( INSTITUTION_ID IS NOT NULL AND ESTABLISHMENT = 'Y') OR (   INSTITUTION_ID IS NULL AND ESTABLISHMENT IS NULL)
)

table.viewSql:
SELECT
  /*00*/ O.offender_id,
  /*01*/ crn,
  /*02*/ CASE D.table_name
    WHEN 'OFFENDER'                     THEN NULL
    WHEN 'ADDRESS_ASSESSMENT'           THEN NULL
    WHEN 'ADDRESSASSESSMENT'            THEN NULL
    WHEN 'ASSESSMENT'                   THEN R1.event_id
    WHEN 'APPROVED_PREMISES_REFERRAL'   THEN APR.event_id
    WHEN 'CASE_ALLOCATION'              THEN CAL.event_id
    WHEN 'CONTACT'                      THEN C.event_id
    WHEN 'COURT_REPORT'                 THEN CA.event_id
    WHEN 'EVENT'                        THEN D.primary_key_id
    WHEN 'INSTITUTIONAL_REPORT'         THEN D1.event_id
    WHEN 'PERSONAL_CIRCUMSTANCE'        THEN NULL
    WHEN 'PERSONAL_CONTACT'             THEN NULL
    WHEN 'PERSONALCONTACT'              THEN NULL
    WHEN 'NSI'                          THEN N.event_id
    WHEN 'REFERRAL'                     THEN R.event_id
    WHEN 'UPW_APPOINTMENT'              THEN D2.event_id
    ELSE NULL
  END                                                           AS event_id,
  /*03*/ D.created_datetime,
  /*04*/ D.last_updated_user_id,
  /*05*/ D.created_provider_id,
  /*06*/ D.last_upd_author_provider_id,
  /*07*/ D.last_saved,
  --DOCMIGRATIONSUPPORT.getProbationArea(d.last_updated_user_id)  AS probation_area_id,
  /*08*/ CASE D.table_name
    WHEN 'ADDRESS_ASSESSMENT'           THEN 'ADDRESSASSESSMENT'
    WHEN 'ADDRESSASSESSMENT'            THEN 'ADDRESSASSESSMENT'
    WHEN 'ASSESSMENT'                   THEN 'ASSESSMENT'
    WHEN 'APPROVED_PREMISES_REFERRAL'   THEN 'APREFERRAL'
    WHEN 'REFERRAL'                     THEN 'REFERRAL'
    WHEN 'COURT_REPORT'                 THEN 'COURTREPORT'
    WHEN 'INSTITUTIONAL_REPORT'         THEN 'INSTITUTIONALREPORT'
    WHEN 'CONTACT'                      THEN 'CONTACT'
    WHEN 'PERSONAL_CONTACT'             THEN 'PERSONALCONTACT'
    WHEN 'OFFENDER'                     THEN 'OFFENDER'
    WHEN 'EVENT'                        THEN 'EVENT'
    WHEN 'NSI'                          THEN CASE WHEN NT.rate_card_flag = 'Y' THEN 'RATECARDINTERVENTION' ELSE 'PROCESSCONTACT' END
    WHEN 'PERSONAL_CIRCUMSTANCE'        THEN 'PERSONALCIRCUMSTANCE'
    WHEN 'UPW_APPOINTMENT'              THEN 'UPWAPPOINTMENT'
    ELSE D.table_name
  END                                                           AS entity_type,
  /*09*/ D.table_name,
  /*10*/ D.primary_key_id                                       AS entity_id,
  /*11*/ 'DOCUMENT'                                             AS document_type,
  /*12*/ D.document_name                                        AS file_name,
  /*13*/ D.document_id                                          AS source_table_key,
  /*14*/ CASE D.status
    WHEN 'Y' THEN 'Y'
    ELSE 'N'
  END                                                           AS locked,
  /*15*/ CASE d.work_in_progress
    WHEN 'Y' THEN 'Y'
    ELSE 'N'
  END                                                           AS reserved,
  /*16*/ CASE D.soft_deleted
    WHEN 0 THEN 'N'
    ELSE 'Y'
  END                                                           AS deleted,
  /*17*/ CASE D.soft_deleted
    WHEN 1 THEN 'Y'
    ELSE ALFRESCOSUPPORT.row_soft_deleted(D.table_name, D.primary_key_id)
  END                                                           AS soft_deleted,
  --
  /*18*/ D.alfresco_document_id
FROM
  document D
    INNER JOIN offender O ON D.offender_id = O.offender_id
    LEFT OUTER JOIN assessment A1 ON A1.assessment_id = D.primary_key_id AND D.table_name = 'ASSESSMENT'
      LEFT OUTER JOIN referral R1 ON R1.referral_id = A1.referral_id
    LEFT OUTER JOIN approved_premises_referral APR ON APR.approved_premises_referral_id = D.primary_key_id AND D.table_name = 'APPROVED_PREMISES_REFERRAL'
    LEFT OUTER JOIN referral R ON R.referral_id = D.primary_key_id AND D.table_name = 'REFERRAL'
    LEFT OUTER JOIN case_allocation CAL ON CAL.case_allocation_id = D.primary_key_id AND D.table_name = 'CASE_ALLOCATION'
    LEFT OUTER JOIN court_report CR ON CR.court_report_id = D.primary_key_id AND D.table_name = 'COURT_REPORT'
      LEFT OUTER JOIN court_appearance CA ON CA.court_appearance_id = CR.court_appearance_id
    LEFT OUTER JOIN institutional_report IR ON IR.institutional_report_id = D.primary_key_id AND D.table_name = 'INSTITUTIONAL_REPORT'
      LEFT OUTER JOIN custody CUS ON CUS.custody_id = IR.custody_id
        LEFT OUTER JOIN disposal D1 ON D1.disposal_id = CUS.disposal_id
    LEFT OUTER JOIN contact C ON C.contact_id = D.primary_key_id AND D.table_name = 'CONTACT'
    LEFT OUTER JOIN nsi N ON N.nsi_id = D.primary_key_id AND D.table_name = 'NSI'
      LEFT OUTER JOIN r_nsi_type NT ON NT.nsi_type_id = N.nsi_type_id
    LEFT OUTER JOIN upw_appointment UA ON UA.upw_appointment_id = D.primary_key_id AND D.table_name = 'UPW_APPOINTMENT'
      LEFT OUTER JOIN upw_details UD ON UD.upw_details_id = UA.upw_details_id
        LEFT OUTER JOIN disposal D2 ON D2.disposal_id = UD.disposal_id
--
UNION ALL
--
SELECT
  /*00*/ O.offender_id,
  /*01*/ O.crn,
  /*02*/ NULL                                                   AS event_id,
  /*03*/ D.created_datetime,
  /*04*/ D.last_updated_user_id,
  /*05*/ D.created_provider_id,
  /*06*/ D.last_upd_author_provider_id,
  /*07*/ D.last_saved,
  /*08*/ 'OFFENDER'                                             AS entity_type,
  /*09*/ 'PRECON'                                               AS table_name,
  /*10*/ O.offender_id                                          AS entity_id,
  /*11*/ 'PREVIOUS_CONVICTION'                                  AS document_type,
  /*12*/ D.document_name                                        AS file_name,
  /*13*/ O.offender_id                                           AS source_table_key,
  /*14*/ 'N'                                                    AS locked,
  /*15*/ 'N'                                                    AS reserved,
  /*16*/ 'N'                                                    AS deleted,
  /*17*/ CASE D.soft_deleted
    WHEN 1 THEN 'Y'
    ELSE ALFRESCOSUPPORT.row_soft_deleted('OFFENDER', O.offender_id)
  END                                                           AS soft_deleted,
  --
  /*18*/ D.alfresco_document_id
FROM
  offender O
    INNER JOIN document D ON D.offender_id = O.offender_id
                         AND D.table_name = 'OFFENDER'
                         AND D.primary_key_id = TO_CHAR(O.offender_id)
                         AND D.document_type = 'PREVIOUS_CONVICTION'
WHERE D.alfresco_document_id IS NOT NULL
--
UNION ALL
--
SELECT
  /*00*/ O.offender_id,
  /*01*/ O.crn,
  /*02*/ E.event_id,
  /*03*/ D.created_datetime,
  /*04*/ D.last_updated_user_id,
  /*05*/ D.created_provider_id,
  /*06*/ D.last_upd_author_provider_id,
  /*07*/ D.last_saved,
  --PKG_LOOKUPS.getusername(event.last_updated_user_id) author,
  /*08*/ 'EVENT'                                                AS entity_type,
  /*09*/ 'CPS'                                                  AS table_name,
  /*10*/ E.event_id                                             AS entity_id,
  /*11*/ 'CPS_PACK'                                             AS document_type,
  /*12*/ D.document_name                                        AS file_name,
  /*13*/ E.event_id                                             AS source_table_key,
  /*14*/ 'N'                                                    AS locked,
  /*15*/ 'N'                                                    AS reserved,
  /*16*/ 'N'                                                    AS deleted,
  /*17*/ CASE D.soft_deleted
    WHEN 1 THEN 'Y'
    ELSE ALFRESCOSUPPORT.row_soft_deleted('EVENT', E.event_id)
  END                                                           AS soft_deleted,
  --
  /*18*/ D.alfresco_document_id
FROM
  event E
    INNER JOIN offender O ON O.offender_id = E.offender_id
    INNER JOIN document D ON D.offender_id = E.offender_id
                         AND D.table_name = 'EVENT'
                         AND D.primary_key_id = TO_CHAR(E.event_id)
                         AND D.document_type = 'CPS_PACK'
WHERE D.alfresco_document_id IS NOT NULL
  --AND E.soft_deleted = 0
